1	const forEachOrthogonalNeighbor = (
2	  x: number,
3	  y: number,
4	  callback: (nx: number, ny: number) => void
5	): void => {
6	  for (let dx = -1; dx <= 1; dx++) {
7	    for (let dy = -1; dy <= 1; dy++) {
8	      if (dx === 0 && dy === 0) continue;
9	      if (dx !== 0 && dy !== 0) continue;
10	      callback(x + dx, y + dy);
11	    }
12	  }
13	};
14	
15	const countLiveOrthogonalNeighbors = (
16	  x: number,
17	  y: number,
18	  liveCells: Set<string>
19	): number => {
20	  let neighbors = 0;
21	  forEachOrthogonalNeighbor(x, y, (nx, ny) => {
22	    if (liveCells.has(`${nx},${ny}`)) {
23	      neighbors++;
24	    }
25	  });
26	  return neighbors;
27	};
28	
29	export function nextGeneration(grid: Array<[number, number]>): Array<[number, number]> {
30	  const survivors: Array<[number, number]> = [];
31	  const liveCells = new Set(grid.map(([x, y]) => `${x},${y}`));
32	  const births: Array<[number, number]> = [];
33	  const deadCellsToCheck = new Set<string>();
34	
35	  // Check survivors and collect dead cells around them
36	  for (const [x, y] of grid) {
37	    const neighborCount = countLiveOrthogonalNeighbors(x, y, liveCells);
38	
39	    if (neighborCount === 2 || neighborCount === 3) {
40	      survivors.push([x, y]);
41	    }
42	
43	    // Add dead neighbors to check for birth
44	    forEachOrthogonalNeighbor(x, y, (nx, ny) => {
45	      if (!liveCells.has(`${nx},${ny}`)) {
46	        deadCellsToCheck.add(`${nx},${ny}`);
47	      }
48	    });
49	  }
50	
51	  // Check dead cells for birth
52	  for (const cellStr of deadCellsToCheck) {
53	    const [xStr, yStr] = cellStr.split(",");
54	    const x = parseInt(xStr);
55	    const y = parseInt(yStr);
56	    const neighborCount = countLiveOrthogonalNeighbors(x, y, liveCells);
57	    if (neighborCount === 3) {
58	      births.push([x, y]);
59	    }
60	  }
61	
62	  return [...survivors, ...births];
63	}
